/* ---- helper: build a zone classifier ---- */
function zonesFor(zones) {
  // zones: [{max, label, color}], last one open-ended
  return (value) => {
    for (const z of zones) {
      if (value <= z.max) return z;
    }
    return zones[zones.length - 1];
  };
}

