function classify(metricKey, value, sexo) {
  if (value === null || value === undefined || value === "" || isNaN(value)) return null;
  const def = REF[metricKey];
  if (!def) return null;
  const zoneList = def.zones[sexo] || def.zones.F;
  for (const z of zoneList) {
    if (value <= z.max) return { ...z, def };
  }
  return { ...zoneList[zoneList.length - 1], def };
}

/* ---- Ideal weight (Devine formula, imperial) used only to compute "peso a controlar" ----
   heightIn: altura total en pulgadas. Retorna libras (lb). ---- */
function calcIdealWeight(heightIn, sexo) {
  const baseKg = sexo === "M" ? 50 : 45.5;
  const idealKg = baseKg + 2.3 * (heightIn - 60);
  return idealKg * 2.20462; // kg -> lb
}

/* ---- Ideal body fat % range midpoint by sex & age, used for "relación de grasa a controlar" ---- */
function idealBodyFatMid(sexo, edad) {
  // Rough age-adjusted healthy midpoints
  let mid;
  if (sexo === "M") {
    if (edad < 30) mid = 12;
    else if (edad < 40) mid = 14;
    else if (edad < 50) mid = 16;
    else if (edad < 60) mid = 18;
    else mid = 19;
  } else {
    if (edad < 30) mid = 21;
    else if (edad < 40) mid = 23;
    else if (edad < 50) mid = 25;
    else if (edad < 60) mid = 27;
    else mid = 28;
  }
  return mid;
}

function calcAge(birthDateStr, evalDateStr) {
  if (!birthDateStr) return null;
  const birth = new Date(birthDateStr);
  const evalD = evalDateStr ? new Date(evalDateStr) : new Date();
  let age = evalD.getFullYear() - birth.getFullYear();
  const m = evalD.getMonth() - birth.getMonth();
  if (m < 0 || (m === 0 && evalD.getDate() < birth.getDate())) age--;
  return age;
}

function generateRecommendations(d) {
  const recs = [];
  const bmiZone = classify("bmi", d.bmi, d.sexo);
  const bfrZone = classify("bfr", d.bfr, d.sexo);
  const viscZone = classify("visceralFat", d.grasaVisceral, d.sexo);
  const waterZone = classify("bodyWater", d.bodyWater, d.sexo);

  recs.push({
    cat: "Nutrición",
    text:
      bmiZone && bmiZone.label === "Obeso"
        ? "Prioriza un déficit calórico moderado y proteína en cada comida."
        : bmiZone && bmiZone.label === "Bajo Peso"
        ? "Aumenta densidad calórica con grasas saludables y más proteína."
        : "Mantén tu balance calórico actual y ajusta según tu objetivo.",
  });
  recs.push({
    cat: "Actividad Física",
    text:
      bfrZone && (bfrZone.label === "Alto" || bfrZone.label === "Aceptable")
        ? "Suma 2-3 sesiones semanales de fuerza para preservar masa muscular."
        : "Mantén tu ritmo actual; varía estímulos para evitar estancamiento.",
  });
  recs.push({
    cat: "Hidratación",
    text:
      waterZone && waterZone.label === "Bajo"
        ? "Aumenta tu ingesta diaria de agua; tu hidratación está bajo el rango ideal."
        : "Tu hidratación está en rango saludable; sostén el hábito.",
  });
  recs.push({ cat: "Sueño", text: "Apunta a 7-9 horas de sueño consistente para optimizar recuperación." });
  recs.push({ cat: "Estrés", text: "Incluye 10 minutos diarios de respiración consciente para bajar cortisol." });
  recs.push({
    cat: "Longevidad",
    text:
      viscZone && viscZone.label !== "Normal"
        ? "Reducir tu grasa visceral es tu palanca de longevidad más importante ahora."
        : "Tu grasa visceral en rango normal es una base sólida para longevidad a largo plazo.",
  });
  recs.push({ cat: "Suplementación", text: "Considera omega-3, vitamina D y proteína de calidad según tu objetivo." });
  recs.push({ cat: "Hábitos", text: "Registra tu progreso semanalmente para mantener consistencia." });

  return recs;
}


/* ====================================================================
   CANVAS RENDERER — dibuja el reporte completo a 1080x1920
   ==================================================================== */


function roundRect(ctx, x, y, w, h, r) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.arcTo(x + w, y, x + w, y + h, r);
  ctx.arcTo(x + w, y + h, x, y + h, r);
  ctx.arcTo(x, y + h, x, y, r);
  ctx.arcTo(x, y, x + w, y, r);
  ctx.closePath();
}

function drawGauge(ctx, cx, cy, radius, value, max, zones, valueLabel, sublabel) {
  ctx.save();
  zones.forEach((z) => {
    const startAngle = Math.PI - (z.from / max) * Math.PI;
    const endAngle = Math.PI - (z.to / max) * Math.PI;
    ctx.beginPath();
    ctx.arc(cx, cy, radius, endAngle, startAngle);
    ctx.strokeStyle = z.color;
    ctx.lineWidth = 22;
    ctx.lineCap = "butt";
    ctx.stroke();
  });
  // needle
  const angle = Math.PI - (Math.min(value, max) / max) * Math.PI;
  const nx = cx + radius * 0.78 * Math.cos(angle);
  const ny = cy - radius * 0.78 * Math.sin(angle);
  ctx.beginPath();
  ctx.moveTo(cx, cy);
  ctx.lineTo(nx, ny);
  ctx.strokeStyle = COLORS.white;
  ctx.lineWidth = 5;
  ctx.lineCap = "round";
  ctx.stroke();
  ctx.beginPath();
  ctx.arc(cx, cy, 8, 0, Math.PI * 2);
  ctx.fillStyle = COLORS.white;
  ctx.fill();
  ctx.restore();

  ctx.textAlign = "center";
  ctx.fillStyle = COLORS.white;
  ctx.font = "800 40px Arial";
  ctx.fillText(valueLabel, cx, cy + 50);
  ctx.fillStyle = COLORS.gray;
  ctx.font = "600 18px Arial";
  ctx.globalAlpha = 0.75;
  ctx.fillText(sublabel.toUpperCase(), cx, cy + 78);
  ctx.globalAlpha = 1;
}

function drawCircularScore(ctx, cx, cy, radius, score, color, label) {
  ctx.save();
  ctx.beginPath();
  ctx.arc(cx, cy, radius, 0, Math.PI * 2);
  ctx.strokeStyle = "#1a1a1a";
  ctx.lineWidth = 24;
  ctx.stroke();

  const endAngle = -Math.PI / 2 + (score / 100) * Math.PI * 2;
  ctx.beginPath();
  ctx.arc(cx, cy, radius, -Math.PI / 2, endAngle);
  ctx.strokeStyle = color;
  ctx.lineWidth = 24;
  ctx.lineCap = "round";
  ctx.stroke();
  ctx.restore();

  ctx.textAlign = "center";
  ctx.fillStyle = COLORS.white;
  ctx.font = "900 64px Arial";
  ctx.fillText(score, cx, cy + 15);
  ctx.fillStyle = color;
  ctx.font = "800 22px Arial";
  ctx.fillText(label.toUpperCase(), cx, cy + 50);
}

function drawHBar(ctx, x, y, w, h, pct, color, trackColor = "#1a1a1a") {
  roundRect(ctx, x, y, w, h, h / 2);
  ctx.fillStyle = trackColor;
  ctx.fill();
  const fillW = Math.max(h, (Math.min(100, pct) / 100) * w);
  roundRect(ctx, x, y, fillW, h, h / 2);
  ctx.fillStyle = color;
  ctx.fill();
}

function drawDonut(ctx, cx, cy, radius, segments) {
  let start = -Math.PI / 2;
  const total = segments.reduce((s, seg) => s + seg.value, 0);
  segments.forEach((seg) => {
    const slice = (seg.value / total) * Math.PI * 2;
    ctx.beginPath();
    ctx.arc(cx, cy, radius, start, start + slice);
    ctx.lineWidth = 46;
    ctx.strokeStyle = seg.color;
    ctx.stroke();
    start += slice;
  });
}

function drawAvatarSilhouette(ctx, x, y, w, h, active, color) {
  const scale = w / 50;
  ctx.save();
  ctx.translate(x, y);
  ctx.scale(scale, scale);
  ctx.fillStyle = active ? color : "#3a3a3a";
  // head
  ctx.beginPath();
  ctx.ellipse(25, 10, 9, 10, 0, 0, Math.PI * 2);
  ctx.fill();
  ctx.restore();
}

function wrapText(ctx, text, x, y, maxWidth, lineHeight) {
  const words = text.split(" ");
  let line = "";
  let lines = 0;
  for (let n = 0; n < words.length; n++) {
    const testLine = line + words[n] + " ";
    const metrics = ctx.measureText(testLine);
    if (metrics.width > maxWidth && n > 0) {
      ctx.fillText(line, x, y + lines * lineHeight);
      line = words[n] + " ";
      lines++;
    } else {
      line = testLine;
    }
  }
  ctx.fillText(line, x, y + lines * lineHeight);
  return lines + 1;
}

